insert into fitness_categories (title, description, sort_order) values
('Fortified Physio — Physical Therapy', 'Free physical therapy for all Butte County first responder staff and volunteers.', 1),
('Brazilian Jiu Jitsu',                 'Drop-in BJJ training for sworn staff at multiple Butte County locations.', 2),
('Yoga 911',                            'Evidence-based yoga and meditation designed for first responders. Saturdays at 10:45 AM.', 3),
('Fight Forward Kickboxing',            'Open to all agency staff. Drop-in M–F. Cardio + strength training.', 4),
('Lord''s Gym — Oroville',             'Drop-in sessions for all agency staff in Oroville.', 5),
('Acupuncture',                         'Up to 4 covered sessions per year for all staff.', 6),
('North Rim CrossFit',                  'Free drop-in CrossFit classes for Butte County first responders.', 7),
('Elevate Health and Performance',      'CrossFit-style group fitness in Paradise. 6 daily class times.', 8),
('Perspire Sauna Studio',               'Private infrared sauna suites with red light therapy. Up to 8 sessions at no cost.', 9);
insert into fitness_items (category_id, title, item_type, content, description, address, sort_order) values
(1, 'About the Service',   'info', 'Physical therapy through Fortified Physio is a free service offered to the staff and volunteers of all First Responding agencies in Butte County. Appointments are filled with detailed assessments, skilled treatments, and uninterrupted 1-on-1 sessions. Out-of-network PT is also available for spouses, kids, and other family at the Chico Clinic location.', null, null, 1);
insert into fitness_items (category_id, title, item_type, url, sort_order) values
(1, 'Schedule an Appointment', 'link', 'https://fortifiedphysio.janeapp.com/', 2);
insert into fitness_items (category_id, title, item_type, description, address, sort_order) values
(1, 'Chico Clinic', 'location', 'Available to ALL agency employees and volunteers.', '629 Entler Ave., #44, Chico, CA 95928', 3),
(1, 'BCSO — South County', 'location', 'Available to ALL agency employees and volunteers.', 'BCSO South County location', 4),
(1, 'Chico PD Location', 'location', 'Available to CPD staff and volunteers ONLY.', 'Chico PD facility', 5);
insert into fitness_items (category_id, title, item_type, content, sort_order) values
(1, 'About Dr. Kelsey Mosier PT, DPT, CF-L1', 'info', 'Dr. Kelsey Mosier was born and raised in Paradise, California, and received her Doctorate of Physical Therapy from South College in June 2020. Kelsey is the founder of Fortified Physio and is passionate about the population she serves. Her treatment approach includes skilled hands-on techniques and functional exercise. When Kelsey is outside of the clinic you can find her exploring the outdoors, at her local CrossFit gym, or hanging out with her husband and 3 dogs.', 6),
(1, 'About Dr. Michael Ellis PT, DPT, CERT-CMFA', 'info', 'Michael is a co-founder and physical therapist at Fortified Physio. He graduated from CSU Chico in 2014 with a bachelor''s degree in exercise physiology, then attended the University of the Pacific and graduated in 2017 with his Doctorate in Physical Therapy. Michael has completed an orthopedic residency and holds a Clinical Management of the Fitness Athlete certification. He practices Brazilian Jiu Jitsu and holds a blue belt.', 7);
insert into fitness_items (category_id, title, item_type, description, address, sort_order) values
(2, 'Cultivate Power Fighting Arts', 'location', 'BJJ classes open to sworn staff only.', '1790 Montgomery St., Oroville, CA 95965', 1),
(2, 'BJJ at Americana', 'location', 'Drop-in sessions for all sworn staff. Identify yourself as sworn LE staff when checking in.', '13306 Cabin Hallow Court, Suite 100, Chico', 2),
(2, 'BJJ at StandAlone MMA', 'location', 'Drop-in sessions for LE sworn staff. Identify yourself as sworn LE when checking in.', '849 W. 9th St., Chico', 3),
(2, 'Oroville BJJ Academy', 'location', 'Drop-in sessions for all sworn staff. Identify yourself as sworn LE when checking in.', '2020 Bird St., Oroville', 4);
insert into fitness_items (category_id, title, item_type, description, address, hours, sort_order) values
(3, 'Classes at The Pilates Barre', 'location', 'Open to staff, volunteers, spouses, and children over the age of 13.', '1905 Notre Dame Blvd., Ste. 170, Chico 95928', 'Saturdays · 10:45 AM', 1);
insert into fitness_items (category_id, title, item_type, content, sort_order) values
(3, 'About Yoga 911 & Danyel Hurd', 'info', 'Danyel Hurd is a Registered Emergency Dept. Nurse and founder of Yoga.911, previously a Field Medic and Nurse in the US Army. The mission of Yoga.911 is to increase awareness of the power of yoga and meditation by educating a network of professionals to share evidence-based practices. Yoga.911 is an integrative, adaptive, and comprehensive practice designed for all students and all levels.', 2);
insert into fitness_items (category_id, title, item_type, description, address, hours, website, sort_order) values
(4, 'Fight Forward — Chico', 'location', 'Open to all agency staff. No need to schedule — classes are drop-in Monday through Friday.', 'Chico, CA', 'Drop-in · Mon–Fri', 'https://www.fightforwardchico.com/#our-story', 1);
insert into fitness_items (category_id, title, item_type, description, address, website, sort_order) values
(5, 'Lord''s Gym', 'location', 'Drop-in sessions available for all agency staff. Please identify yourself as an agency staff member when checking in.', '2120 Bird St., Oroville', 'https://www.lordsgymoroville.org/', 1);
insert into fitness_items (category_id, title, item_type, description, address, phone, sort_order) values
(6, 'American Chi Center for Health', 'location', 'All staff can receive up to 4 acupuncture sessions per year. Call to schedule.', 'Chico, CA', '(530) 342-2895', 1);
insert into fitness_items (category_id, title, item_type, content, sort_order) values
(7, 'How to Get Started', 'info', 'Step 1: Visit northrimcrossfit.com and sign up for a "No-Sweat" intro. Step 2: Meet with one of our coaches. Step 3: Start working out! Drop-in costs are covered for agency staff. NRCF also offers special rates for Public Safety spouses and families.', 1);
insert into fitness_items (category_id, title, item_type, description, address, hours, website, sort_order) values
(7, 'North Rim CrossFit', 'location', 'Specialized programming for first responders. All coaches hold CrossFit Level 1, Level 2, or Olympic Weightlifting certifications.', 'Chico, CA', 'Mon–Fri · 5:00 AM–6:45 PM · Sat 9:00–11:00 AM', 'https://www.northrimcrossfit.com/schedule', 2);
insert into fitness_items (category_id, title, item_type, description, address, hours, phone, sort_order) values
(8, 'Elevate Health and Performance', 'location', 'Group workout functional fitness gym offering CrossFit-style workouts with a focus on injury prevention. Text or call before your first class.', '797 Elliott Rd, Ste K, Paradise, CA 95969', 'Mon–Fri · 5:00 AM · 6:00 AM · 9:00 AM · 10:00 AM · 4:00 PM', '(209) 642-9448', 1);
insert into fitness_items (category_id, title, item_type, content, sort_order) values
(9, 'Booking & Rates', 'info', 'Agency staff are eligible for up to 8 sessions at no cost. After 8 sessions: $20 per session. Spouses of first responders can also utilize this benefit at $20 per session. Call to book and mention the Wellness Unit to receive these rates.', 1);
insert into fitness_items (category_id, title, item_type, description, address, phone, sort_order) values
(9, 'Perspire Sauna Studio — Chico', 'location', 'Private infrared sauna suites with medical-grade red light therapy. Regular sauna use can help reduce stress, improve sleep, support muscle recovery, boost circulation, and promote overall well-being.', 'Chico, CA', '(530) 861-6134', 2);
